import{_ as a,o as e,c as d,a3 as o}from"./chunks/framework.BTFg6ESq.js";const b=JSON.parse('{"title":"Web Canvas (进阶指南)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/web-canvas/advanced.md","filePath":"user-guide/tools/web-canvas/advanced.md","lastUpdated":1778221347000}'),i={name:"user-guide/tools/web-canvas/advanced.md"};function r(n,t,l,s,c,h){return e(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="web-canvas-进阶指南" tabindex="-1">Web Canvas (进阶指南) <a class="header-anchor" href="#web-canvas-进阶指南" aria-label="Permalink to &quot;Web Canvas (进阶指南)&quot;">​</a></h1><p>Web Canvas 的核心价值在于其 <strong>Physical-First</strong> 架构下的深度协作能力。本指南将深入探讨 Agent 联动、预览引擎原理、版本控制及自定义模板等进阶功能。</p><h2 id="agent-协作工作流" tabindex="-1">Agent 协作工作流 <a class="header-anchor" href="#agent-协作工作流" aria-label="Permalink to &quot;Agent 协作工作流&quot;">​</a></h2><h3 id="绑定画布" tabindex="-1">绑定画布 <a class="header-anchor" href="#绑定画布" aria-label="Permalink to &quot;绑定画布&quot;">​</a></h3><p>在 LLM 聊天设置中找到 <strong>&quot;绑定画布 ID&quot;</strong> 配置项，输入项目大厅中显示的画布 ID 即可完成绑定。绑定后，Agent 在生成代码时会直接操作画布文件，而非仅输出文本建议。</p><h3 id="agent-可操作的能力" tabindex="-1">Agent 可操作的能力 <a class="header-anchor" href="#agent-可操作的能力" aria-label="Permalink to &quot;Agent 可操作的能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>功能</th><th>典型使用场景</th></tr></thead><tbody><tr><td><code>read_canvas_file</code></td><td>读取文件（带行号）</td><td>Agent 审查现有代码</td></tr><tr><td><code>apply_canvas_diff</code></td><td>应用 Search/Replace Diff</td><td>Agent 精准修改指定代码块</td></tr><tr><td><code>write_canvas_file</code></td><td>全量写入文件</td><td>Agent 创建新文件或重写整个文件</td></tr><tr><td><code>commit_changes</code></td><td>提交所有更改</td><td>Agent 完成一轮修改后创建 Git 快照</td></tr><tr><td><code>discard_changes</code></td><td>丢弃未提交变更</td><td>回退 Agent 的修改</td></tr><tr><td><code>list_canvas_files</code></td><td>获取文件树</td><td>Agent 了解项目结构</td></tr><tr><td><code>create_canvas</code></td><td>创建新画布</td><td>Agent 主动新建项目</td></tr><tr><td><code>clear_runtime_errors</code></td><td>清空运行时错误</td><td>修复问题后清理错误记录</td></tr><tr><td><code>open_window</code></td><td>打开预览窗口</td><td>为指定画布开启独立预览</td></tr></tbody></table><h3 id="agent-驱动的代码生成工作流" tabindex="-1">Agent 驱动的代码生成工作流 <a class="header-anchor" href="#agent-驱动的代码生成工作流" aria-label="Permalink to &quot;Agent 驱动的代码生成工作流&quot;">​</a></h3><ol><li>在 LLM 聊天中绑定 Web Canvas（设置中填入画布 ID）</li><li>用自然语言描述需求，如&quot;帮我创建一个带有交互式折线图的数据仪表盘&quot;</li><li>Agent 会自动创建文件、写入代码</li><li>你可以在预览窗口中实时查看效果</li><li>不满意时直接告诉 Agent 修改，它会使用 <code>apply_canvas_diff</code> 精确调整指定代码块</li><li>满意后 Agent 调用 <code>commit_changes</code> 提交版本</li></ol><h3 id="审批系统-preview-→-approve-reject" tabindex="-1">审批系统（Preview → Approve/Reject） <a class="header-anchor" href="#审批系统-preview-→-approve-reject" aria-label="Permalink to &quot;审批系统（Preview → Approve/Reject）&quot;">​</a></h3><p>Agent 的操作会经过审批系统：</p><ol><li><strong>预览阶段</strong>：Agent 调用的 <code>apply_canvas_diff</code> 或 <code>write_canvas_file</code> 会<strong>直接执行</strong>到磁盘，让你在预览中实时看到效果</li><li><strong>用户确认</strong>：你确认修改是否正确，选择<strong>批准</strong>或<strong>拒绝</strong></li><li><strong>拒绝回滚</strong>：如果拒绝，系统自动回滚——新文件被物理删除，已有文件通过 Git checkout 恢复</li></ol><h3 id="运行时错误自动注入" tabindex="-1">运行时错误自动注入 <a class="header-anchor" href="#运行时错误自动注入" aria-label="Permalink to &quot;运行时错误自动注入&quot;">​</a></h3><p>开启&quot;自动包含运行时错误&quot;设置后，预览中的运行时错误会自动注入到 Agent 上下文中。Agent 获取上下文时能看到类似以下信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--- RUNTIME ERRORS ---</span></span>
<span class="line"><span>TypeError: Cannot read property &#39;data&#39; of undefined</span></span>
<span class="line"><span>  at Line 24:12 (index.js)</span></span>
<span class="line"><span>---</span></span></code></pre></div><p>这样 Agent 可以&quot;看见&quot;自己代码的问题并自动修复。你可以在设置中调整最大错误数量（0–50）来控制 token 消耗。</p><h3 id="隐式创建" tabindex="-1">隐式创建 <a class="header-anchor" href="#隐式创建" aria-label="Permalink to &quot;隐式创建&quot;">​</a></h3><p>如果当前没有打开的画布，Agent 执行文件操作时会自动创建一个新画布，确保协作流程不会中断。</p><hr><h2 id="模板系统" tabindex="-1">模板系统 <a class="header-anchor" href="#模板系统" aria-label="Permalink to &quot;模板系统&quot;">​</a></h2><h3 id="内置模板" tabindex="-1">内置模板 <a class="header-anchor" href="#内置模板" aria-label="Permalink to &quot;内置模板&quot;">​</a></h3><p>系统内置了多分类模板，在创建画布时可选：</p><table tabindex="0"><thead><tr><th>分类</th><th>说明</th><th>示例模板 ID</th></tr></thead><tbody><tr><td>基础</td><td>干净的空 HTML 模板</td><td><code>blank-html</code></td></tr><tr><td>动效</td><td>CSS 动画、Canvas 渲染模板</td><td><code>canvas-animation</code></td></tr><tr><td>数据可视化</td><td>集成 ECharts 等图表库的模板</td><td><code>echarts-dashboard</code></td></tr><tr><td>游戏</td><td>轻量游戏开发模板</td><td><code>snake-game</code></td></tr><tr><td>作品集</td><td>个人展示页模板</td><td><code>portfolio-page</code></td></tr><tr><td>工具</td><td>实用工具类模板</td><td><code>json-pretty-viewer</code></td></tr><tr><td>用户自定义</td><td>用户自己创建的模板</td><td>自定义存储路径</td></tr></tbody></table><h3 id="模板版本管理" tabindex="-1">模板版本管理 <a class="header-anchor" href="#模板版本管理" aria-label="Permalink to &quot;模板版本管理&quot;">​</a></h3><p>模板通过 <code>template.json</code> 中的 <code>version</code> 字段管理版本。应用启动时，内置模板会同步到 <code>AppData/canvases/templates/builtin/</code> 目录下，仅在版本更新时覆盖旧文件。</p><h3 id="自定义模板" tabindex="-1">自定义模板 <a class="header-anchor" href="#自定义模板" aria-label="Permalink to &quot;自定义模板&quot;">​</a></h3><p>你可以将自己的项目目录结构创建为模板。用户自定义模板存放在 <code>{appDataDir}/canvases/templates/user/{templateId}/</code> 目录下。</p><p>创建自定义模板的步骤：</p><ol><li>在 <code>{appDataDir}/canvases/templates/user/</code> 下创建一个以模板 ID 命名的目录</li><li>在该目录下创建 <code>template.json</code>，定义模板元数据（名称、描述、入口文件、版本）</li><li>在该目录下创建 <code>files/</code> 子目录，放入所有项目文件</li><li>重启 Web Canvas 或重新加载，在新建画布时就能看到自定义模板选项</li></ol><blockquote><p>TODO: 截图 - 自定义模板目录结构示例</p></blockquote><h3 id="设置默认模板" tabindex="-1">设置默认模板 <a class="header-anchor" href="#设置默认模板" aria-label="Permalink to &quot;设置默认模板&quot;">​</a></h3><p>你可以在 Web Canvas 设置页面的<strong>项目管理</strong>中配置&quot;默认项目模板&quot;的 ID。创建新项目时会自动预选该模板。</p><hr><h2 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to &quot;版本控制&quot;">​</a></h2><p>每个画布项目内置一个独立的 Git 仓库。当你创建画布时，系统自动执行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git init → git add &lt;all files&gt; → git commit -m &quot;Initial commit from template: {name}&quot;</span></span></code></pre></div><h3 id="提交更改" tabindex="-1">提交更改 <a class="header-anchor" href="#提交更改" aria-label="Permalink to &quot;提交更改&quot;">​</a></h3><p>在编辑器左侧的待更改面板中点击 <strong>Commit All</strong>，输入提交信息即可。提交操作：</p><ol><li>通过 Git 内部服务检查所有文件的状态矩阵</li><li>添加未跟踪文件（new）和修改过的文件（modified）</li><li>执行 Git commit</li><li>更新元数据文件的 <code>updatedAt</code> 时间戳</li><li>更新项目索引</li><li>刷新状态栏</li></ol><blockquote><p>TODO: 截图 - 待更改面板上的 Commit 按钮和提交信息输入</p></blockquote><h3 id="丢弃更改" tabindex="-1">丢弃更改 <a class="header-anchor" href="#丢弃更改" aria-label="Permalink to &quot;丢弃更改&quot;">​</a></h3><p>点击 <strong>Discard</strong> 按钮会通过 <code>git checkout</code> 恢复到最近一次提交的状态。这是一个不可逆操作——所有未提交的修改都会丢失，请谨慎操作。</p><h3 id="查看变更" tabindex="-1">查看变更 <a class="header-anchor" href="#查看变更" aria-label="Permalink to &quot;查看变更&quot;">​</a></h3><p>左侧文件树中的每个文件都会显示 Git 状态标识：</p><ul><li><strong><code>new</code>（绿色）</strong>：新创建但未提交的文件</li><li><strong><code>modified</code>（橙色）</strong>：已有文件被修改</li><li><strong><code>deleted</code>（红色）</strong>：文件被删除</li></ul><hr><h2 id="预览引擎深入" tabindex="-1">预览引擎深入 <a class="header-anchor" href="#预览引擎深入" aria-label="Permalink to &quot;预览引擎深入&quot;">​</a></h2><h3 id="架构原理" tabindex="-1">架构原理 <a class="header-anchor" href="#架构原理" aria-label="Permalink to &quot;架构原理&quot;">​</a></h3><p>预览引擎使用 iframe 通过 <code>srcdoc</code> 属性渲染入口文件。它会自动在 HTML 中注入：</p><ul><li><code>&lt;base&gt;</code> 标签：确保相对路径资源（图片、CSS、JS 文件）正确加载</li><li>错误捕获脚本：劫持 <code>console</code> 方法（<code>warn</code>/<code>error</code>）和全局错误事件（<code>window.onerror</code>、<code>unhandledrejection</code>）</li></ul><p>预览通信机制：预览 iframe 通过 <code>window.parent.postMessage()</code> 将运行时错误回传到主窗口，主窗口的去重和限流机制确保不会淹没日志。</p><h3 id="预览配置" tabindex="-1">预览配置 <a class="header-anchor" href="#预览配置" aria-label="Permalink to &quot;预览配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>自动打开预览</td><td>创建或打开项目后自动开启独立预览窗口</td><td>开启</td></tr><tr><td>预览刷新延迟</td><td>文件保存后等待多久刷新预览</td><td>500ms</td></tr></tbody></table><h3 id="独立预览窗口" tabindex="-1">独立预览窗口 <a class="header-anchor" href="#独立预览窗口" aria-label="Permalink to &quot;独立预览窗口&quot;">​</a></h3><p>预览窗口是一个由 Rust 后端创建的系统级 <code>WebviewWindow</code>，独立于主应用运行。这意味着：</p><ul><li>预览窗口关闭后不会影响编辑器状态</li><li>可以同时打开多个画布的预览窗口</li><li>预览窗口独立于主应用窗口，不会被遮挡</li></ul><hr><h2 id="外部编辑器协同" tabindex="-1">外部编辑器协同 <a class="header-anchor" href="#外部编辑器协同" aria-label="Permalink to &quot;外部编辑器协同&quot;">​</a></h2><p>你可以在 Web Canvas 中配置 VSCode 路径，然后在项目操作菜单中选择 <strong>在 VSCode 中打开</strong>。</p><h3 id="配置-vscode-路径" tabindex="-1">配置 VSCode 路径 <a class="header-anchor" href="#配置-vscode-路径" aria-label="Permalink to &quot;配置 VSCode 路径&quot;">​</a></h3><p>进入 Web Canvas 设置，在<strong>外部编辑器</strong>配置项中填入 <code>code.exe</code> 或 <code>code.cmd</code> 的完整路径。系统会自动扫描常见的 VSCode 安装目录（点击扫描按钮）。</p><h3 id="协同工作流" tabindex="-1">协同工作流 <a class="header-anchor" href="#协同工作流" aria-label="Permalink to &quot;协同工作流&quot;">​</a></h3><ol><li><strong>VSCode 中编辑</strong>：享受完整的 IDE 体验（代码补全、调试、Git 历史）</li><li><strong>Web Canvas 中预览</strong>：回到 Web Canvas 查看实时预览效果</li><li><strong>Web Canvas 感知变更</strong>：Physical-First 架构通过 Git 状态自动感知 VSCode 中的修改，打开项目时自动刷新</li></ol><blockquote><p>TODO: 截图 - 在 VSCode 中编辑画布项目</p></blockquote><hr><h2 id="健康检查与项目修复" tabindex="-1">健康检查与项目修复 <a class="header-anchor" href="#健康检查与项目修复" aria-label="Permalink to &quot;健康检查与项目修复&quot;">​</a></h2><p>Web Canvas 会定期对所有项目执行健康检查，对比磁盘目录和索引文件。可能的状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th><th>修复方式</th></tr></thead><tbody><tr><td>健康</td><td>索引与磁盘一致</td><td>无需操作</td></tr><tr><td>索引异常</td><td>索引存在但磁盘缺失</td><td>移除孤儿索引</td></tr><tr><td>未索引</td><td>磁盘存在但索引缺失</td><td>重新建立索引</td></tr><tr><td>元数据损坏</td><td><code>.canvas.json</code> 文件不可读</td><td>尝试从索引恢复元数据</td></tr></tbody></table><p>鼠标悬停在异常状态标签上会显示修复选项。你也可以在项目大厅中点击刷新按钮手动触发全量健康检查。</p><hr><h2 id="diff-引擎的智能匹配" tabindex="-1">Diff 引擎的智能匹配 <a class="header-anchor" href="#diff-引擎的智能匹配" aria-label="Permalink to &quot;Diff 引擎的智能匹配&quot;">​</a></h2><p>当 Agent 使用 <code>apply_canvas_diff</code> 时，底层的 Diff 引擎采用<strong>降级匹配策略</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>精确匹配 → 忽略末尾空格 → 完全忽略缩进 → 模糊匹配（≥85% 相似度）</span></span></code></pre></div><p>这意味着 Agent 可以容忍代码中的缩进差异和空格变化，有效提高修改成功率。模糊匹配基于 Bigram Dice 系数，对行级别的相似度进行计算，首尾行还有额外加权。</p><p>Diff 操作会返回匹配策略和范围信息，让你了解匹配的准确度：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Applied diff to index.html [fuzzy matched (confidence: 92%)] at lines 15-22</span></span></code></pre></div><hr><h2 id="常见高级问题" tabindex="-1">常见高级问题 <a class="header-anchor" href="#常见高级问题" aria-label="Permalink to &quot;常见高级问题&quot;">​</a></h2><h3 id="q-agent-操作被拒绝后文件会怎样" tabindex="-1">Q：Agent 操作被拒绝后文件会怎样？ <a class="header-anchor" href="#q-agent-操作被拒绝后文件会怎样" aria-label="Permalink to &quot;Q：Agent 操作被拒绝后文件会怎样？&quot;">​</a></h3><p>Agent 的操作被拒绝后：</p><ul><li><strong>修改已有文件</strong>：通过 Git checkout 恢复到修改前的状态</li><li><strong>新建文件</strong>：从磁盘物理删除</li><li><strong>多个连续操作</strong>：被拒绝的操作会尝试回滚，但建议在审批前仔细确认预览效果</li></ul><p>如果误拒绝了正确修改，可通过编辑器重新手动修改。</p><h3 id="q-如何强制刷新健康检查" tabindex="-1">Q：如何强制刷新健康检查？ <a class="header-anchor" href="#q-如何强制刷新健康检查" aria-label="Permalink to &quot;Q：如何强制刷新健康检查？&quot;">​</a></h3><p>在项目大厅中点击右上角的刷新按钮，触发全量健康检查。系统会重新扫描 <code>AppData/canvases/projects/</code> 目录下的所有项目，更新索引和元数据。</p><h3 id="q-预览窗口能展示非-html-文件吗" tabindex="-1">Q：预览窗口能展示非 HTML 文件吗？ <a class="header-anchor" href="#q-预览窗口能展示非-html-文件吗" aria-label="Permalink to &quot;Q：预览窗口能展示非 HTML 文件吗？&quot;">​</a></h3><p>预览引擎默认加载入口文件（通常为 <code>index.html</code>）。如果需要预览其他类型的文件（如 SVG 或服务端渲染页面），你需要创建一个包装 HTML 文件来引用它们。</p>`,86)])])}const u=a(i,[["render",r]]);export{b as __pageData,u as default};
